customCss:
/* ====================================================================
   PREMIUM CUSTOM CSS FOR MERMAID DIAGRAMS (OPTIMIZED FOR DARK THEME)
   ==================================================================== */

/* 1. Globalne style, typografia i tło */
.mermaid svg,
svg[id^="mermaid-"] {
    font-family: 'Inter', -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif !important;
    background: #141416 !important; /* Wymuszenie ciemnego tła całego wykresu */
}

/* 2. Klasy i boksy (Class Diagram & Flowchart Nodes) */
g.classGroup rect,
g.classGroup .outer,
g.classGroup .inner,
.node rect,
.node circle,
.node polygon,
.node path,
.classBox {
    fill: #1e1e24 !important;      /* Ciemnografitowe tło boksów */
    stroke: #5856d6 !important;    /* Fioletowa ramka */
    stroke-width: 1.5px !important;
    rx: 6px !important;            /* Zaokrąglone rogi */
    ry: 6px !important;
}

/* Podświetlenie klasy po najechaniu myszką */
g.classGroup:hover rect,
g.classGroup:hover .outer {
    stroke: #9d4edd !important;    /* Jaśniejszy fiolet przy hover */
    filter: drop-shadow(0 0 6px rgba(157, 78, 221, 0.6)) !important;
}

/* Węzły warunkowe (Diamenty / Decyzje) */
.node.question polygon,
.node.question rect {
    fill: #2c251e !important;      /* Ciemnobursztynowe tło */
    stroke: #ff9500 !important;    /* Pomarańczowa ramka */
}

/* 3. Wymuszenie jasnego tekstu (Overriding inline tspan/text styles) */
g.classGroup text,
g.classGroup tspan,
g.classGroup .label,
.node text,
.node tspan,
.node .label,
.classText,
.classText tspan,
.title,
.title tspan,
.mermaid text,
.mermaid tspan {
    fill: #ffffff !important;      /* Wymuszenie czystej bieli dla całego tekstu */
    color: #ffffff !important;
    font-size: 13px !important;
    font-weight: 500 !important;
}

/* Pogrubienie nagłówków (tytułów klas) */
g.classGroup .title,
g.classGroup .title tspan,
.node .title,
.title {
    font-weight: 700 !important;
    font-size: 14px !important;
}

/* Linie podziału wewnątrz klas */
g.classGroup line {
    stroke: #3a3a4a !important;    /* Ciemniejsze linie separatorów */
    stroke-width: 1px !important;
}

/* 4. Linie relacji i strzałki (Relationship lines & Arrows) */
.edgePath .path,
.relation,
.relationLine {
    stroke: #8e8e93 !important;    /* Neutralny szary dla linii */
    stroke-width: 1.5px !important;
}

/* Kolor strzałek */
marker,
marker path {
    fill: #8e8e93 !important;
    stroke: none !important;
}

/* 5. Etykiety i teksty relacji (Relationship labels) */
.edgeLabel rect,
.label rect,
g.label rect,
.edgeLabel .label-container,
.edgeLabel rect.label-container {
    fill: #141416 !important;      /* Ciemne tło podtekstu na liniach, aby nie było białych prostokątów */
    stroke: #3a3a4a !important;    /* Ramka etykiety relacji */
    stroke-width: 1px !important;
    rx: 4px !important;
    ry: 4px !important;
}

.edgeLabel text,
.edgeLabel tspan,
.label text,
.label tspan,
.relation text,
.edgeTerminals text,
.edgeTerminals tspan {
    fill: #aeaeb2 !important;      /* Stonowany szary kolor tekstu relacji */
    font-size: 12px !important;
    font-weight: 500 !important;
}
